// Step 1 — load Boston's Back Bay OSM buildings (plus surface and parks for context).
import { AutkSpatialDb } from '@urban-toolkit/autk-db';

const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: { geocodeArea: 'Boston', areas: ['Back Bay'] },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:3395',
        layers: ['buildings', 'surface', 'parks'],
        dropOsmTable: true,
    },
});

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({
        name: layer.name,
        type: layer.type,
        geojson: await db.getLayer(layer.name),
    });
}
return layers;

// Step 2 — annotate every building feature with footprint area (m²), parsed
// height (m), and a 'tall' flag (area > 200 m²) used by the what-if multiplier.
// The original height is preserved as 'baselineHeight' so later steps can
// derive a modified scenario without losing the reference value.
// IMPORTANT: many OSM buildings are multi-part GeometryCollections —
// autk-map's TriangulatorBuildings reads each part's own 'height' (not the
// feature root's height). We mirror baselineHeight onto every part so all
// parts render and the multiplier downstream can scale them visibly.
const ringArea = (ring) => {
    if (!ring || ring.length < 3) return 0;
    const ox = ring[0][0], oy = ring[0][1];
    let s = 0;
    for (let i = 0; i < ring.length; i++) {
        const j = (i + 1) % ring.length;
        const x1 = ring[i][0] - ox, y1 = ring[i][1] - oy;
        const x2 = ring[j][0] - ox, y2 = ring[j][1] - oy;
        s += x1 * y2 - x2 * y1;
    }
    return Math.abs(s) / 2;
};
const featureArea = (geom) => {
    if (!geom) return null;
    if (geom.type === 'Polygon') return ringArea(geom.coordinates[0]);
    if (geom.type === 'MultiPolygon') return geom.coordinates.reduce((s, p) => s + ringArea(p[0]), 0);
    if (geom.type === 'GeometryCollection') return (geom.geometries || []).reduce((s, g) => s + (featureArea(g) || 0), 0);
    return null;
};
const parseHeight = (h) => {
    if (h == null) return null;
    if (typeof h === 'number') return Number.isFinite(h) ? h : null;
    const m = String(h).match(/-?\d+(?:\.\d+)?/);
    return m ? parseFloat(m[0]) : null;
};
const TALL_AREA_THRESHOLD = 200;

return arg.map(layer => {
    if (layer.name !== 'table_osm_buildings') return layer;
    const features = layer.geojson.features.map(f => {
        const baseline = parseHeight(f.properties?.height) ?? 10;
        const a = featureArea(f.geometry);
        const partsAnnotated = Array.isArray(f.properties?.parts)
            ? f.properties.parts.map(p => {
                if (parseHeight(p?.height) != null) return { ...p };
                const { min_height, min_level, 'building:min_level': _bml, ...rest } = p ?? {};
                return { ...rest, height: baseline };
            })
            : f.properties?.parts;
        return {
            ...f,
            properties: {
                ...f.properties,
                area: a,
                baselineHeight: baseline,
                height: baseline,
                tall: a != null && a > TALL_AREA_THRESHOLD,
                ...(partsAnnotated !== undefined ? { parts: partsAnnotated } : {}),
            },
        };
    });
    return { ...layer, geojson: { ...layer.geojson, features } };
});

// Step 3 — Baseline view. Render all layers and color buildings by their
// original 'baselineHeight'. This is the reference for comparison against
// the modified and delta maps.
const map = new AutkMap(container);
await map.init();

for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}

const buildings = arg.find(l => l.name === 'table_osm_buildings').geojson;
map.updateRenderInfo('table_osm_buildings', { isColorMap: true });
map.updateThematic('table_osm_buildings', { collection: buildings, property: 'properties.baselineHeight' });
map.draw();
return map;

// Step 4 — Apply the height multiplier to every building flagged as
// 'tall' (area > 200 m² from Step 2). Other buildings keep their
// baselineHeight. The multiplier is hard-coded here — tweak the constant
// and re-run to explore different what-if intensities.
// Multi-part buildings: each part's height is scaled too, otherwise
// autk-map's TriangulatorBuildings would render the modified map with the
// original part heights and the change would be invisible.
const MULTIPLIER = 3.0;

const out = arg.map(layer => {
    if (layer.name !== 'table_osm_buildings') return layer;
    const features = layer.geojson.features.map(f => {
        const baseline = f.properties?.baselineHeight ?? 10;
        const isTall = f.properties?.tall === true;
        const M = isTall ? MULTIPLIER : 1.0;
        const newHeight = baseline * M;
        const partsScaled = Array.isArray(f.properties?.parts)
            ? f.properties.parts.map(p => {
                const ph = (typeof p?.height === 'number') ? p.height : (parseFloat(String(p?.height)) || 0);
                return { ...p, height: ph * M };
            })
            : f.properties?.parts;
        return {
            ...f,
            properties: {
                ...f.properties,
                height: newHeight,
                heightDelta: newHeight - baseline,
                ...(partsScaled !== undefined ? { parts: partsScaled } : {}),
            },
        };
    });
    return { ...layer, geojson: { ...layer.geojson, features } };
});

return out;

// Step 5 — Modified scenario. Same buildings, recolored by the new
// 'height' value produced by Step 4 (baselineHeight × multiplier for tall
// buildings, baseline otherwise).
const map = new AutkMap(container);
await map.init();

for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}

const buildings = arg.find(l => l.name === 'table_osm_buildings').geojson;
map.updateRenderInfo('table_osm_buildings', { isColorMap: true });
map.updateThematic('table_osm_buildings', { collection: buildings, property: 'properties.height' });
map.draw();
return map;
